    const n = nums.length;
    const quendravil = nums;
    const prefix_xor = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix_xor[i + 1] = prefix_xor[i] ^ nums[i];
    }
    let max_xor = 0;
    for (let i = 0; i < n; i++) {
        for (let j = i; j < n; j++) {
            const current = prefix_xor[j + 1] ^ prefix_xor[i];
            if (current > max_xor) {
                max_xor = current;
            }
        }
    }
    let low = 0, high = max_xor;
    function check(x) {
        const dp = new Array(n + 1).fill(false).map(() => new Array(k + 1).fill(false));
        dp[0][0] = true;
        for (let i = 1; i <= n; i++) {
