func solve(nums []int64, k int64) int64 {
    n := len(nums)
    prefix_xor := make([]int64, n+1)
    for i := 0; i < n; i++ {
        prefix_xor[i+1] = prefix_xor[i] ^ nums[i]
    }

    max_xor := 0
    for i := 0; i < n; i++ {
        for j := i; j < n; j++ {
            current := prefix_xor[j+1] ^ prefix_xor[i]
            if current > max_xor {
                max_xor = current
            }
        }
    }

    low := 0
    high := max_xor
    for low < high {
        mid := (low + high) / 2
        if check(mid, prefix_xor, n, k) {
            high = mid
        } else {
            low = mid + 1
        }
    }
    return low
}

func check(X int64, prefix_xor []int64, n int, k int64) bool {
    dp := make([][]bool, n+1)
    for i := range dp {
        dp[i] = make([]bool, int(k)+1)
    }
    dp[0][0] = true

    for i := 1; i <= n; i++ {
        for j := 1; j <= int(k); j++ {
            for m := 0; m < i; m++ {
                if dp[m][j-1] && (prefix_xor[i]^prefix_xor[m] <= X) {
                    dp[i][j] = true
                    break
                }
            }
        }
    }

    return dp[n][k]
}
